import numpy as np
from scipy.interpolate import pchip_interpolate
from scipy.signal import butter, sosfiltfilt
from enum import IntEnum

class SkinContactConfidence(IntEnum):
    NO_CONTACT = 0
    LOW_CONFIDENCE = 1
    MODERATE_CONFIDENCE = 2
    HIGH_CONFIDENCE = 3

class SkinContact(IntEnum):
    OFF_SKIN = 0
    ON_SKIN = 1

class PPGSignalDecomposition():
    def __init__(self,
                 bits_resolution = 12,
                 sampling_rate = 25,
                 diff_edge_threshold = None,    # 1st derivative threshold within the detection window to mark a rising edge as candidate
                 max_sse = None,                # maximum allowed deviation when comparing wavelets (measured in sum of square error) to group them
                 max_jitter_sec = 0.1,          # maximum jitter in time allowed between wavelets in dual channel when finding common wavelets
                 spo2_a: float = -11.55662048527909,
                 spo2_b: float = 104.26367177880022
        ):
        self.bits_resolution = bits_resolution
        self.sampling_rate = sampling_rate

        self.min_hr = 38    # minimum heart rate (bpm)
        self.max_hr = 200   # maximum heart rate (bpm)

        # TODO: make this adaptive? Dependent on SNR?

        # 1st derivative threshold, all points in the window should pass this requirement to mark as potential upstroke
        if diff_edge_threshold is not None:
            self.diff_edge_threshold = diff_edge_threshold
        elif self.bits_resolution == 12:
            self.diff_edge_threshold = 1.3
        else:
            self.diff_edge_threshold = (2**self.bits_resolution) * 0.0006

        # moving window width for detecting upstroke = 0.04 sec, minimum 2 samples
        self.upstroke_window_size = np.max([int(np.ceil(self.sampling_rate * 0.04)), 2])

        self.mon_threshold = self.diff_edge_threshold * 0.01           # monotonicity in the window
        self.diff_head_threshold = self.diff_edge_threshold * -0.05    # threshold to detect starting of the pulse wave
        self.max_look_back = self.upstroke_window_size * 3             # maximum number of points to look back when finding foot of pulse wave (local min)

        self.max_wavelet_len = 60 * self.sampling_rate / self.min_hr
        self.min_wavelet_len = 60 * self.sampling_rate / self.max_hr
        self.max_tilt = (2**self.bits_resolution) * 0.25
        self.max_tilt_amp_ratio = 0.7

        # TODO: may need adjustment for different resolution
        if self.bits_resolution <= 12:
            self.clipping_percentage = 0.05
        elif self.bits_resolution < 16:
            self.clipping_percentage = 0.03
        else:
            self.clipping_percentage = 0.01

        # TODO: the signal is flipped.... so clipping doesn't behave as I thought.
        # maybe I should support flipped signal (e.g. downward stroke instead of upward)
        self.clipping_treshold = int((2 ** self.bits_resolution) * (1 - self.clipping_percentage))

        # Thresholds for relative differences
        # +/-25% of the edge height
        self.upstroke_rel_diff_target = 0.25
        # +/-18 BPM heart rate
        self.hr_rel_diff_target = 18

        # TODO: max_sse is hardcoded, should it be configurable?
        # self.max_sse = 0.35 * (self.sampling_rate/60)

        if max_sse is not None:
            self.max_sse = max_sse
        else:
            self.max_sse = 0.85 * (self.sampling_rate/60)
       
        # Maximum allowed jitter (in samples) when looking for common slices in dual channel processing
        self.max_jitter = int(self.sampling_rate * max_jitter_sec)

        # SpO2 equation coefficients
        self.spo2_a = spo2_a
        self.spo2_b = spo2_b

    def get_wavelets(self, signal, filter_signal: bool = False):
        if type(signal) == list:
            signal = np.array(signal)

        if filter_signal:
            high_cutoff: float = 220/60
            low_cutoff: float = 30/60
            filter_order: int = 8
            sos = butter(filter_order, [low_cutoff, high_cutoff], btype="bandpass", fs=self.sampling_rate, output='sos')

            
            n_sections, m = sos.shape
            ntaps = 2 * n_sections + 1
            ntaps -= min((sos[:, 2] == 0).sum(), (sos[:, 5] == 0).sum())
            min_padlen = ntaps * 3

            if len(signal) < min_padlen:
                return {
                "slices": np.array([[],[],[]], dtype=int),
                "removed_slices": np.array([[],[],[]], dtype=int),
                "removed_edges": np.array([[],[]], dtype=int),
                "aligned_eavelets": np.array([[],[]]),
                "normalized_signal": np.array([]),
                "top_envelope": np.array([]),
                "bottom_envelope": np.array([]),
                "hr": None,
            }
            
            signal = sosfiltfilt(sos, signal)

        slices, removed_edges = self._extract_markers(signal)

        if slices.size == 0:
            return {
                "slices": np.array([[],[],[]], dtype=int),
                "removed_slices": np.array([[],[],[]], dtype=int),
                "removed_edges": removed_edges,
                "aligned_eavelets": np.array([[],[]]),
                "normalized_signal": np.array([]),
                "top_envelope": np.array([]),
                "bottom_envelope": np.array([]),
                "hr": None,
            }

        slices, removed_slices = self._clean_up_markers(signal, slices)

        if (slices.ndim == 2) and (slices.shape[1] > 0):
            normalized_signal, top_envelope, bottom_envelope = self._normalize_waveform(signal, slices)
        else:
            removed_slices = np.hstack((removed_slices, slices))
            # sort the 2D array
            removed_slices = removed_slices[:,np.argsort(removed_slices[0,:])]

            return {
                "slices": np.array([[],[],[]], dtype=int),
                "removed_slices": removed_slices,
                "removed_edges": removed_edges,
                "aligned_eavelets": np.array([[],[]]),
                "normalized_signal": np.array([]),
                "top_envelope": np.array([]),
                "bottom_envelope": np.array([]),
                "hr": None,
            }

        aligned_wavelets, selected_slices, hr = self._final_selection(normalized_signal, slices)

        if selected_slices.size > 0:
            removed_slices = np.hstack((removed_slices, np.delete(slices, selected_slices, axis=1)))
            slices = slices[:, selected_slices]
        else:
            removed_slices = np.hstack((removed_slices, slices))
            slices = np.array([[],[],[]], dtype=int)


        # return selected_slices, removed_slices, hr, top_envelope, bottom_envelope

        return {
            "slices": slices,
            "removed_slices": removed_slices,
            "removed_edges": removed_edges,
            "aligned_eavelets": aligned_wavelets,
            "normalized_signal": normalized_signal,
            "top_envelope": top_envelope,
            "bottom_envelope": bottom_envelope,
            "hr": hr,
        }

    def get_wavelets_windowed(self, signal, window_size_sec: float, overlap_sec: float, filter_signal: bool = False):
        if not isinstance(signal, np.ndarray):
            signal = np.array(signal)

        length = len(signal)
        window_size = int(window_size_sec * self.sampling_rate)
        overlap = int(overlap_sec * self.sampling_rate)
        step = window_size - overlap

        slices = np.array([[],[],[]], dtype=int)
        removed_slices = np.array([[],[],[]], dtype=int)
        hr = np.array([])

        for i in range(0, length - window_size + 1, step):
            ret = self.get_wavelets(signal[i : i + window_size], filter_signal=filter_signal)
            removed_slices = np.hstack((removed_slices, ret["removed_slices"]))
            if ret["slices"].ndim != 2 or ret["slices"].shape[1] == 0:
                continue

            # append found slices in segment to the accumulator if it's not yet in it
            for col in range(ret["slices"].shape[1]):
                current_foot, current_sys, current_tail = ret["slices"][:,col] + i

                # exact match
                if np.sum((slices[0,:] == current_foot) & (slices[1,:] == current_sys) & (slices[2,:] == current_tail)):
                    #   ("exact match, skip")
                    continue

                # the slice's foot is in another slice interval
                if np.sum((slices[0,:] <= current_foot) & (slices[2,:] > current_foot)):
                    # print("NOT exact match, it's between markers, skip")
                    continue
                
                # new marker from the overlap
                if slices.shape[1] > 0 and slices[0,-1] > current_foot:
                    # print("new marker from overlap, skip")
                    continue

                slices = np.hstack((slices, np.array([[current_foot], [current_sys], [current_tail]], dtype=int)))
                hr = np.append(hr, ret["hr"])
            
        
        # TODO: LAST slice

        if slices.shape[1] == 0:
            return {
                "slices": np.array([[],[],[]], dtype=int),
                "removed_slices": removed_slices,
                "normalized_signal": np.array([]),
                "top_envelope": np.array([]),
                "bottom_envelope": np.array([]),
                "hr": None,
            }

        normalized_signal, top_envelope, bottom_envelope = self._normalize_waveform(signal, slices)

        return {
            "slices": slices,
            "removed_slices": removed_slices,
            "normalized_signal": normalized_signal,
            "top_envelope": top_envelope,
            "bottom_envelope": bottom_envelope,
            "hr": np.mean(hr),
        }
    
    def dual_channel_aligned_slices(self, signal_ir: np.ndarray, slices_ir: np.ndarray, signal_red: np.ndarray, slices_red: np.ndarray):
        if not isinstance(slices_ir, np.ndarray) or not isinstance(slices_red, np.ndarray):
            raise ValueError("Input arrays should be numpy arrays")
        
        if slices_ir.ndim != 2 or slices_ir.shape[1] == 0 or slices_red.ndim != 2 or slices_red.shape[1] == 0:
            return {
                "slices_ir": np.array([[],[],[]], dtype=int),
                "slices_red": np.array([[],[],[]], dtype=int),
                "pi_ir": np.array([[]]),
                "pi_red": np.array([[]]),
                "r": np.array([]),
                "spo2": np.array([]),
                "hr": np.array([]),
            }
        
        selected_ir = np.array([], dtype=int)
        selected_red = np.array([], dtype=int)
        for col in range(slices_ir.shape[1]):
            same_as_col = (np.abs(slices_red[0,:] - slices_ir[0, col]) < 2) & (np.abs(slices_red[2,:] - slices_ir[2, col]) <= self.max_jitter)
            if any(same_as_col):
                selected_ir = np.append(selected_ir, col)
                selected_red = np.append(selected_red, np.argwhere(same_as_col).ravel())
        
        
        if selected_ir.size == 0 or selected_red.size == 0:
            return {
                "slices_ir": np.array([[],[],[]], dtype=int),
                "slices_red": np.array([[],[],[]], dtype=int),
                "pi_ir": np.array([[]]),
                "pi_red": np.array([[]]),
                "r": np.array([]),
                "spo2": np.array([]),
                "hr": np.array([]),
            }
        
        selected_ir = slices_ir[:, selected_ir]
        selected_red = slices_red[:, selected_red]
        
        # For raw waveform: R_x = (sys_marker - dia_marker) / dia_marker
        r_red = np.array([np.abs(signal_red[selected_red[1,col]]-signal_red[selected_red[0,col]])/signal_red[selected_red[1,col]] for col in range(selected_red.shape[1])])
        r_ir = np.array([np.abs(signal_ir[selected_ir[1,col]]-signal_ir[selected_ir[0,col]])/signal_ir[selected_ir[1,col]] for col in range(selected_ir.shape[1])])
        r_final = r_red / r_ir
        spo2 = self.spo2_a * r_final + self.spo2_b

        hr = [round(60 * self.sampling_rate / (selected_ir[2, col] - selected_ir[0, col]), 1) for col in range(selected_ir.shape[1])]

        return {
            "slices_ir": selected_ir,
            "slices_red": selected_red,
            "pi_red": np.round(r_red * 100, 1),
            "pi_ir": np.round(r_ir * 100, 1),
            "r": r_final,
            "spo2": spo2,
            "hr": hr
        }

    def run(self, signal_ir: np.ndarray,  signal_red: np.ndarray, window_size_sec: float = 10.0, overlap_sec: float = 5.0, flip_signals: bool = False, filter_signals: bool = False, skin_contact_threshold: SkinContactConfidence = SkinContactConfidence.LOW_CONFIDENCE):
        if flip_signals:
            ir_sliced = self.get_wavelets_windowed((-1) * signal_ir, window_size_sec, overlap_sec, filter_signal=filter_signals)
            red_sliced = self.get_wavelets_windowed((-1) * signal_red, window_size_sec, overlap_sec, filter_signal=filter_signals)
        else:
            ir_sliced = self.get_wavelets_windowed(signal_ir, window_size_sec, overlap_sec, filter_signal=filter_signals)
            red_sliced = self.get_wavelets_windowed(signal_red, window_size_sec, overlap_sec, filter_signal=filter_signals)

        common_slices = self.dual_channel_aligned_slices(signal_ir=signal_ir, slices_ir=ir_sliced["slices"], signal_red=signal_red, slices_red=red_sliced["slices"])

        if ir_sliced["slices"].shape[1] == 0 and red_sliced["slices"].shape[1] == 0:
            return {
                "skin_contact": SkinContact.OFF_SKIN,
                "red_slices": red_sliced["slices"],
                "ir_slices": ir_sliced["slices"],
                "red_removed_slices": red_sliced["removed_slices"],
                "ir_removed_slices": ir_sliced["removed_slices"],
                "common_slices_red": common_slices["slices_red"],
                "common_slices_ir": common_slices["slices_ir"],
                "pi_red": common_slices["pi_red"],
                "pi_ir": common_slices["pi_ir"],
                "r": common_slices["r"],
                "spo2": common_slices["spo2"],
                "hr": common_slices["hr"],
            }

        confidence = SkinContactConfidence.LOW_CONFIDENCE

        if common_slices["slices_ir"].shape[1] >= 3:
            confidence = SkinContactConfidence.MODERATE_CONFIDENCE
        
        total_time_of_found_slices = np.sum([common_slices["slices_ir"][2, col] - common_slices["slices_ir"][0, col] for col in range(common_slices["slices_ir"].shape[1])], dtype=int)

        # Covered at least half of the signal
        if total_time_of_found_slices / signal_ir.size >= 0.5:
            confidence = SkinContactConfidence.HIGH_CONFIDENCE
        
        skin_contact = SkinContact.ON_SKIN if confidence >= skin_contact_threshold else SkinContact.OFF_SKIN
        
        return {
            "skin_contact": skin_contact,
            "red_slices": red_sliced["slices"],
            "ir_slices": ir_sliced["slices"],
            "red_removed_slices": red_sliced["removed_slices"],
            "ir_removed_slices": ir_sliced["removed_slices"],
            "common_slices_red": common_slices["slices_red"],
            "common_slices_ir": common_slices["slices_ir"],
            "pi_red": common_slices["pi_red"],
            "pi_ir": common_slices["pi_ir"],
            "r": common_slices["r"],
            "spo2": common_slices["spo2"],
            "hr": common_slices["hr"],
        }

    # TODO: Should we break it up to smaller functions for each stage?
    def _extract_markers(self, waveform: np.ndarray):
        ### Stage I: Find potential upstrokes/edges and mark their 'Systolic' and 'Diastolic' positions
        i = 0
        sys_markers = []
        dia_markers = []

        # start with diastolic marker
        finding_dia_marker = True
        max_num = waveform.size
        while i < (max_num -1) :
            if finding_dia_marker: # State: looking for foot marker
                if i >= max_num - self.upstroke_window_size:
                    # done with extracting markers
                    break

                diff1 = np.diff(waveform[i:i+self.upstroke_window_size])

                # diff2 = np.diff(diff1)
                #TO CHECK if min(diff1 >= diff1Treshold) && min(diff2 <= monTreshold) # potential upstroke?

                # found a potential rising edge, all points in window are moving faster than threshold
                if all(diff1 >= self.diff_edge_threshold):
                    k = i
                    i = i + self.upstroke_window_size - 1
                    while (k > 0) and ((i-self.upstroke_window_size-k) < self.max_look_back):
                        if ((waveform[k-1] - waveform[k]) >= self.diff_head_threshold):   # foot of a pulse (local min)
                            if not np.isin(k,dia_markers): # not in the list yet, put it in
                                dia_markers.append(k)
                                finding_dia_marker = False
                                break
                        else:
                            k = k - 1
                else:
                    i = i + 1

            else: # State: looking for peak marker
                if (waveform[i+1] - waveform[i]) <= 0:  # found pulse peak (local max)
                    if not np.isin(i,sys_markers):      # not in the list yet, put it in
                        sys_markers.append(i)
                        finding_dia_marker = True
                else:
                    i = i + 1

        # Remove edges which are clipping (sysMarker higher then clippingTreshold)
        sys_markers = np.array(sys_markers, dtype=int)
        dia_markers = np.array(dia_markers, dtype=int)
        clipping_edges = np.argwhere(waveform[sys_markers] > self.clipping_treshold)
        removed_edges = np.array([dia_markers[clipping_edges].ravel().tolist(), sys_markers[clipping_edges].ravel().tolist()], dtype=int)
        dia_markers = np.delete(dia_markers, clipping_edges)
        sys_markers = np.delete(sys_markers, clipping_edges)

        if (sys_markers.size < 3) or (dia_markers.size < 4):
            return np.array([], dtype=int), removed_edges

        ### Stage II: Decide which edges to keep

        # Group similar amplitude edges together (more likely to be similar wavelets)
        # Find starting group: biggest group of most similar edge amplitudes
        # up to sys_markers.size in case we detected a lonely dia marker
        amplitudes = waveform[sys_markers] - waveform[dia_markers[:sys_markers.size]]
        relative_diffs = np.abs(amplitudes - amplitudes[:, np.newaxis]) / amplitudes
        near_sets = [np.array(relative_diffs[relative_diffs[:,i] < self.upstroke_rel_diff_target, i]) for i in range(amplitudes.size)]

        # Assemble decision matrix
        # set i: mean | std | size | i
        decision_matrix = np.array([[np.mean(x), np.std(x), x.size, i] for i,x in enumerate(near_sets)]).transpose()

        # sort/filter decision matrix
        # A: sort descending by number of similar edges
        # decision_matrix = decision_matrix[:,(-decision_matrix[2,:]).argsort()]
        # B: leave only the edges with the most and 2nd most number of similar edges
        decision_matrix = decision_matrix[:, decision_matrix[2,:] >= decision_matrix[2,:].max() - 1]
        
        # select the initial group by the smallest mean rel_diff
        initial_group = np.array(np.where(relative_diffs[:,int(decision_matrix[3, decision_matrix[0,:].argmin()])] < self.upstroke_rel_diff_target), dtype='int32').ravel()
            
        groups = [initial_group]
        leftover_edges = np.delete(range(amplitudes.size), np.isin(range(amplitudes.size), initial_group))
        
        # Group the rest of the edges
        while leftover_edges.size > 0:
            # comparing to farthest edge in group
            best_fit_group_rel_diff_per_edge = np.array([[e, np.min(np.array([np.max(relative_diffs[g,e]) for g in groups]))] for e in leftover_edges]).transpose()
            selected_edge_index = np.argmin(best_fit_group_rel_diff_per_edge[1,:])
            selected_edge = int(best_fit_group_rel_diff_per_edge[0,selected_edge_index])

            # if it fits, add to the group
            if best_fit_group_rel_diff_per_edge[1,selected_edge_index] < self.upstroke_rel_diff_target:
                group_index = np.argmin(np.array([[np.max(relative_diffs[g, selected_edge])] for g in groups]))
                groups[group_index] = np.append(groups[group_index],selected_edge)
            
            # if not, create a new group
            else:
                groups.append(np.array([selected_edge]))

            leftover_edges = np.delete(leftover_edges, leftover_edges == selected_edge)

        
        if len(groups) > 1:
            group_size_desc = np.array([(-1)*x.size for x in groups]).argsort()
            group_mean_ampl = [np.mean(amplitudes[x]) for x in groups]

            # if the first two largest groups are similar size, keep the larger amplitude group
            if ((groups[group_size_desc[0]].size - groups[group_size_desc[1]].size) < 3) and (group_mean_ampl[group_size_desc[1]] > group_mean_ampl[group_size_desc[0]]):
                to_keep = np.array(groups.pop(group_size_desc[1]))
            else:
                to_keep = np.array(groups.pop(group_size_desc[0]))
            to_delete = np.concatenate(groups)
        else:
            to_keep = groups[0]
            to_delete = np.array([], dtype=int)
        
        to_keep.sort()
        to_delete.sort()
        
        if (to_keep.size < 3):
            return np.array([], dtype=int), removed_edges
        
        ### Stage III: Make Wavelets (Slices)
        
        # Too small (noise) edges disturb wavelet formation
        # Keep removed edges above treshold
        # min_amp = np.mean(amplitudes[to_keep]) * 0.3
        min_amp = np.max(amplitudes[to_keep]) * 0.3
        rem = amplitudes[to_delete] < min_amp
        removed_edges = np.hstack((removed_edges, np.vstack((dia_markers[to_delete[rem]], sys_markers[to_delete[rem]]))))
        to_delete = np.delete(to_delete,rem)    
        
        if dia_markers[np.max(to_keep)] == dia_markers[-1]:
            to_delete = np.append(to_delete, np.max(to_keep))
            to_keep = np.delete(to_keep, to_keep == max(to_keep))
        
        all_edges = np.append(to_keep, to_delete)
        all_edges.sort()
        all_edges = np.append(all_edges, dia_markers.size - 1)
        slices = np.array([[dia_markers[e], sys_markers[e], dia_markers[all_edges[np.where(all_edges == e)[0].astype(int).item(0)+1]]] for e in to_keep], dtype=int).transpose()

        removed_edges = np.hstack((removed_edges, np.vstack((dia_markers[to_delete], sys_markers[to_delete]))))
            
        if slices.shape[1] < 3:
            removed_edges = np.hstack((removed_edges, slices[0:2,:]))
            slices = np.array([])
            return slices, removed_edges

        ### Stage IV: Keep similar Pulse Rate wavelets
        pulse_rates = 60 * self.sampling_rate / (slices[2,:] - slices[0,:])
        relative_diffs = np.abs(pulse_rates - pulse_rates[:, np.newaxis])
        near_sets_pr = [np.array(relative_diffs[relative_diffs[:,i] < self.hr_rel_diff_target, i]) for i in range(pulse_rates.size)]
        decision_matrix = np.array([[np.mean(x), np.std(x), x.size, i] for i,x in enumerate(near_sets_pr)]).transpose()
        # leave only the wavelets with the most number of similar wavelets
        decision_matrix = decision_matrix[:,decision_matrix[2,:] == np.max(decision_matrix[2,:])]
        # If there are more potential groups left, choose the one with minimum mean difference
        initial_group = np.array(np.where(relative_diffs[:,int(decision_matrix[3, decision_matrix[0,:].argmin()])] < self.hr_rel_diff_target), dtype=int).ravel()
        removed_edges = np.hstack((removed_edges, slices[0:2,np.delete(range(pulse_rates.size),initial_group)]))
        slices = slices[:,initial_group]
        
        return slices, removed_edges
        
    def _clean_up_markers(self, signal, slices):
        # remove slices if they are below minimum or above maximum sample size
        lengths = slices[2,:] - slices[0,:]
        removed_slices = slices[:, (lengths < self.min_wavelet_len) | (lengths > self.max_wavelet_len)]
        slices = slices[:, ~((lengths < self.min_wavelet_len) | (lengths > self.max_wavelet_len))]

        # remove slices where the tilt (difference in value at the two ends) is too large (>max_tilt)
        # or tilt/amplitude ratio is bigger than max_tilt_amp_ratio
        tilts = np.abs(signal[slices[2,:]] - signal[slices[0,:]])
        amps = (signal[slices[1,:]] - signal[slices[0,:]])
        tilt_amp_ratio = tilts / amps
        removed_slices = np.hstack((removed_slices, slices[:, (tilts > self.max_tilt) | (tilt_amp_ratio > self.max_tilt_amp_ratio)]))
        slices = slices[:, ~((tilts > self.max_tilt) | (tilt_amp_ratio > self.max_tilt_amp_ratio))]

        return slices, removed_slices

    def _normalize_waveform(self, signal, slices: np.ndarray):
        if (signal.size == 0) or (slices.ndim != 2) or (slices.shape[1] < 3):
            return np.array([]), np.array([]), np.array([])

        # Get markers and values
        sys_markers = slices[1,:]
        sys_values = signal[sys_markers]
        dia_markers = np.unique(np.append(slices[0,:], slices[2,:]))
        dia_values = signal[dia_markers]
        
        # Start of the envelopes to be the same heights as the first markers
        sys_markers = np.append(0, sys_markers)
        sys_values  = np.append(sys_values[0], sys_values)
        dia_markers = np.append(0, dia_markers)
        dia_values  = np.append(dia_values[0], dia_values)


        # Insert sys_marker height at the dia_marker position
        # if two wavelets are far from each other then insert a marker at the end (height of the sysMarker) to avoid deformation
        # TODO: threshold hardcoded to 0.6, does it have to be configurable?
        for i in range(slices.shape[1] - 1):
            current_pos = np.where(sys_markers == slices[1,i])[0].astype(int).ravel()
        
            if (i < slices.shape[1] and (slices[0,i+1] - slices[2,i]) > (slices[2,i] - slices[0,i])*0.6 ) or (i == slices.shape[1]):
                sys_markers = np.insert(sys_markers, current_pos+1, slices[2,i])
                sys_values = np.insert(sys_values, current_pos+1, signal[slices[2,i]] + (signal[slices[1,i]] - signal[slices[0,i]]))

        # End of the envelopes to be the same heights as the last markers
        sys_markers = np.append(sys_markers, dia_markers[-1])
        sys_values = np.append(sys_values, signal[slices[2,-1]] + (signal[slices[1,-1]] - signal[slices[0,-1]]))
        sys_markers = np.append(sys_markers, signal.size-1)
        sys_values = np.append(sys_values, sys_values[-1])
        
        dia_markers = np.append(dia_markers, signal.size-1)
        dia_values = np.append(dia_values, signal[slices[2,-1]])

        # Create envelopes
        top_envelope = pchip_interpolate(sys_markers, sys_values, range(signal.size))
        bottom_envelope = pchip_interpolate(dia_markers, dia_values, range(signal.size))
        
        # Normalize signal
        normalized_signal = np.array([(signal[i] - bottom_envelope[i]) / (top_envelope[i] - bottom_envelope[i]) for i in range(signal.size)])

        return normalized_signal, top_envelope, bottom_envelope

    def _final_selection(self, normalized_signal, slices):    
        if slices.ndim < 2:
            #return aligned_wavelets, selectedSlices, PR
            return np.array([]), np.array([]), 0
        
        num_wavelets = slices.shape[1]
        if num_wavelets < 3:
            #return aligned_wavelets, selected_slices, PR
            return np.array([]), np.array([]), 0
        
        # Align wavelets within the window by their sys marker position
        wavelets_length = slices[2,:] - slices[0,:]
        sys_shift = slices[1,:] - slices[0,:]
        sys_shift = max(sys_shift) - sys_shift
        aligned_wavelets = np.zeros((max(wavelets_length + sys_shift)+1, num_wavelets))
        for i in range(num_wavelets):
            aligned_wavelets[sys_shift[i] : wavelets_length[i] + sys_shift[i], i] = normalized_signal[slices[0,i]:slices[2,i]]
        
        ## Sum of Square Errors
        sse = np.array([np.sum((aligned_wavelets[:,i]-aligned_wavelets[:,j])**2) for i in range(num_wavelets) for j in range(num_wavelets)]).reshape(num_wavelets,num_wavelets)

        near_sets = [np.array(sse[sse[:,i] < self.max_sse, i]) for i in range(sse.shape[0])]
        decision_matrix = np.array([[np.sum(x), np.mean(x), np.std(x), x.size, i] for i,x in enumerate(near_sets)]).transpose()
        # leave only the eavelets with the most and 2nd most number of similar wavelets
        decision_matrix = decision_matrix[:, decision_matrix[3,:] >= decision_matrix[3,:].max()-1]
        initial_group = np.array(np.where(sse[:,int(decision_matrix[4, decision_matrix[0,:].argmin()])] < self.max_sse), dtype=int).ravel()
        
        groups = [initial_group]
        leftover_edges = np.delete(range(sse.shape[0]), np.isin(range(sse.shape[0]), initial_group))
        
        # Group the rest of the wavelets
        while leftover_edges.size > 0:
            best_fit_group_rel_diff_per_wavelet = np.array([[e, np.min([[np.max(sse[g,e])] for g in groups])] for e in leftover_edges]).transpose()
            selected_wavelet_index = np.argmin(best_fit_group_rel_diff_per_wavelet[1,:])
            selected_wavelet = int(best_fit_group_rel_diff_per_wavelet[0, selected_wavelet_index])
            # If it fits any group, add it to the group
            if best_fit_group_rel_diff_per_wavelet[1, selected_wavelet_index] < self.max_sse:
                group_index = np.argmin(np.array([[np.max(sse[g, selected_wavelet])] for g in groups]))
                groups[group_index] = np.append(groups[group_index], selected_wavelet)
            # If not, create a new group
            else:
                groups.append(np.array([selected_wavelet]))
            leftover_edges = np.delete(leftover_edges, leftover_edges == selected_wavelet)
        
        # Largest group
        group_size_desc = np.array([(-1)*x.size for x in groups]).argsort()
        selected_slices = np.array(groups.pop(group_size_desc[0]))
        
        if selected_slices.size < 3:
            #return aligned_wavelets, selectedSlices, PR
            return np.array([]), np.array([]), 0
        
        # Calculate HR
        start_avg = np.mean(np.array([np.where(aligned_wavelets[:, i] != 0)[0][0]-1 for i in selected_slices]))
        end_avg = aligned_wavelets.shape[0] - 1 - np.mean(np.array([np.where(np.flip(aligned_wavelets[:, i]) != 0)[0][0]-1 for i in selected_slices]))
        hr = round(60 * self.sampling_rate / (end_avg - start_avg), 1)
        start_avg = int(round(start_avg))
        end_avg = int(round(end_avg))

        return aligned_wavelets, selected_slices, hr

    # TODO: make it static?
    def resample_signal(self, signal, target_size: int):
        if signal.size == 0:
            return np.array([])
        
        dSample = signal.size / target_size
        signal = np.append(signal, signal[-1])  #just in case if the last interpolation would index out of the array
        
        return np.array([((i*dSample)-int(i*dSample))*signal[int(i*dSample)+1] + (1-((i*dSample)-int(i*dSample)))*signal[int(i*dSample)] for i in range(target_size)])
